public struct OnboardingState {
    /**
     * The backend ID selected or entered by the user during BackendSetup.
     */
    public var selectedBackendId: String?
    /**
     * Human-readable progress label during attestation (e.g. "Connecting to backend...").
     * None when attestation is not in progress.
     */
    public var attestationStage: String?
    /**
     * Result of the attestation demo. None until attestation completes.
     */
    public var attestationResult: AttestationStatus?
    /**
     * Human-readable TEE label for the attested backend (e.g. "Intel TDX").
     * None until attestation completes.
     */
    public var attestationTeeLabel: String?
    /**
     * True while the ValidateApiKey health-check is in flight.
     */
    public var validatingApiKey: Bool
    /**
     * Error message from the last failed API key validation. Cleared on retry.
     */
    public var apiKeyError: String?

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(
        /**
         * The backend ID selected or entered by the user during BackendSetup.
         */selectedBackendId: String?, 
        /**
         * Human-readable progress label during attestation (e.g. "Connecting to backend...").
         * None when attestation is not in progress.
         */attestationStage: String?, 
        /**
         * Result of the attestation demo. None until attestation completes.
         */attestationResult: AttestationStatus?, 
        /**
         * Human-readable TEE label for the attested backend (e.g. "Intel TDX").
         * None until attestation completes.
         */attestationTeeLabel: String?, 
        /**
         * True while the ValidateApiKey health-check is in flight.
         */validatingApiKey: Bool, 
        /**
         * Error message from the last failed API key validation. Cleared on retry.
         */apiKeyError: String?) {
        self.selectedBackendId = selectedBackendId
        self.attestationStage = attestationStage
        self.attestationResult = attestationResult
        self.attestationTeeLabel = attestationTeeLabel
        self.validatingApiKey = validatingApiKey
        self.apiKeyError = apiKeyError
    }
}

#if compiler(>=6)
extension OnboardingState: Sendable {}
#endif


extension OnboardingState: Equatable, Hashable {
    public static func ==(lhs: OnboardingState, rhs: OnboardingState) -> Bool {
        if lhs.selectedBackendId != rhs.selectedBackendId {
            return false
        }
        if lhs.attestationStage != rhs.attestationStage {
            return false
        }
        if lhs.attestationResult != rhs.attestationResult {
            return false
        }
        if lhs.attestationTeeLabel != rhs.attestationTeeLabel {
            return false
        }
        if lhs.validatingApiKey != rhs.validatingApiKey {
            return false
        }
        if lhs.apiKeyError != rhs.apiKeyError {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(selectedBackendId)
        hasher.combine(attestationStage)
        hasher.combine(attestationResult)
        hasher.combine(attestationTeeLabel)
        hasher.combine(validatingApiKey)
        hasher.combine(apiKeyError)
    }
}



