/**
 * Error taxonomy for attestation operations -- crosses UniFFI boundary.
 * Mirrors LlmError pattern: thiserror for Display, uniffi::Error for FFI.
 */
public enum AttestationError: Swift.Error {

    
    
    case CollateralFetch(reason: String
    )
    case QuoteVerification(reason: String
    )
    case NonceMismatch(expected: String, actual: String
    )
    case JwtVerification(reason: String
    )
    case CacheFailed(reason: String
    )
    case Unsupported
    case NetworkError(reason: String
    )
    case CacheLockPoisoned
    case UnsupportedTeeType(teeType: String
    )
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeAttestationError: FfiConverterRustBuffer {
    typealias SwiftType = AttestationError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> AttestationError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .CollateralFetch(
            reason: try FfiConverterString.read(from: &buf)
            )
        case 2: return .QuoteVerification(
            reason: try FfiConverterString.read(from: &buf)
            )
        case 3: return .NonceMismatch(
            expected: try FfiConverterString.read(from: &buf), 
            actual: try FfiConverterString.read(from: &buf)
            )
        case 4: return .JwtVerification(
            reason: try FfiConverterString.read(from: &buf)
            )
        case 5: return .CacheFailed(
            reason: try FfiConverterString.read(from: &buf)
            )
        case 6: return .Unsupported
        case 7: return .NetworkError(
            reason: try FfiConverterString.read(from: &buf)
            )
        case 8: return .CacheLockPoisoned
        case 9: return .UnsupportedTeeType(
            teeType: try FfiConverterString.read(from: &buf)
            )

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: AttestationError, into buf: inout [UInt8]) {
        switch value {

        

        
        
        case let .CollateralFetch(reason):
            writeInt(&buf, Int32(1))
            FfiConverterString.write(reason, into: &buf)
            
        
        case let .QuoteVerification(reason):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(reason, into: &buf)
            
        
        case let .NonceMismatch(expected,actual):
            writeInt(&buf, Int32(3))
            FfiConverterString.write(expected, into: &buf)
            FfiConverterString.write(actual, into: &buf)
            
        
        case let .JwtVerification(reason):
            writeInt(&buf, Int32(4))
            FfiConverterString.write(reason, into: &buf)
            
        
        case let .CacheFailed(reason):
            writeInt(&buf, Int32(5))
            FfiConverterString.write(reason, into: &buf)
            
        
        case .Unsupported:
            writeInt(&buf, Int32(6))
        
        
        case let .NetworkError(reason):
            writeInt(&buf, Int32(7))
            FfiConverterString.write(reason, into: &buf)
            
        
        case .CacheLockPoisoned:
            writeInt(&buf, Int32(8))
        
        
        case let .UnsupportedTeeType(teeType):
            writeInt(&buf, Int32(9))
            FfiConverterString.write(teeType, into: &buf)
            
        }
    }
}


