/**
 * Attestation verification status for a backend.
 *
 * Crosses the UniFFI boundary per D-10. Carried in AppState as
 * Vec<(backend_id, AttestationStatus)> per D-11.
 */

public enum AttestationStatus {
    
    /**
     * Cryptographic verification passed (TDX quote, SNP report, or NRAS JWT verified).
     */
    case verified
    /**
     * Not yet checked or no attestation endpoint available for this backend.
     */
    case unverified
    /**
     * Verification was attempted and failed.
     */
    case failed(reason: String
    )
    /**
     * Was verified but TTL has elapsed; re-verification pending.
     */
    case expired
}


#if compiler(>=6)
extension AttestationStatus: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeAttestationStatus: FfiConverterRustBuffer {
    typealias SwiftType = AttestationStatus

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> AttestationStatus {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .verified
        
        case 2: return .unverified
        
        case 3: return .failed(reason: try FfiConverterString.read(from: &buf)
        )
        
        case 4: return .expired
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: AttestationStatus, into buf: inout [UInt8]) {
        switch value {
        
        
        case .verified:
            writeInt(&buf, Int32(1))
        
        
        case .unverified:
            writeInt(&buf, Int32(2))
        
        
        case let .failed(reason):
            writeInt(&buf, Int32(3))
            FfiConverterString.write(reason, into: &buf)
            
        
        case .expired:
            writeInt(&buf, Int32(4))
        
        }
    }
}


