            FfiConverterString.write(reason, into: &buf)
            
        
        case let .AuthError(reason):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(reason, into: &buf)
            
        
        case let .ModelNotFound(modelId):
            writeInt(&buf, Int32(3))
            FfiConverterString.write(modelId, into: &buf)
            
        
